prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo ?endCount WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4ccc3fd711004f519782ac92e58f6ddd" ;
         bbo:name ?modelName ;
         tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  {
    SELECT ?choreo (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
      ?end a bboExt:EndEvent ;
           tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo ?endCount ?startCount WHERE {
  VALUES ?id { "4ccc3fd711004f519782ac92e58f6ddd" }
  ?model a bboExt:Model ;
         tai:normalizedId ?id ;
         bbo:name ?modelName ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  {
    SELECT ?choreo (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
      ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?start) AS ?startCount) WHERE {
      ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?start) AS ?startCount) (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
}
GROUP BY ?choreo ?choreoName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?end ?reachable WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
  ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .
  BIND(EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
  } AS ?reachable)
}
ORDER BY DESC(?reachable)
LIMIT 25
